// Device Fingerprinting Toolkit
// Demonstrates browser identification techniques

function getCanvasFingerprint() {
  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d');
  ctx.textBaseline = 'top';
  ctx.font = '14px Arial';
  ctx.fillText('fingerprint test 🎨', 2, 2);
  ctx.fillStyle = 'rgba(102, 204, 0, 0.7)';
  ctx.fillRect(50, 50, 100, 80);
  return canvas.toDataURL().slice(-50);
}

function getBrowserInfo() {
  return {
    userAgent: navigator.userAgent,
    platform: navigator.platform,
    language: navigator.language,
    languages: navigator.languages,
    cookieEnabled: navigator.cookieEnabled,
    doNotTrack: navigator.doNotTrack,
    hardwareConcurrency: navigator.hardwareConcurrency,
    maxTouchPoints: navigator.maxTouchPoints,
    deviceMemory: navigator.deviceMemory || 'N/A',
  };
}

function getScreenInfo() {
  return {
    width: screen.width,
    height: screen.height,
    colorDepth: screen.colorDepth,
    pixelRatio: window.devicePixelRatio,
    availWidth: screen.availWidth,
    availHeight: screen.availHeight,
  };
}

console.log('=== Device Fingerprint ===');
console.log('Canvas:', getCanvasFingerprint());
console.log('\n=== Browser Info ===');
const info = getBrowserInfo();
Object.entries(info).forEach(([k,v]) => console.log(`  ${k}: ${v}`));
console.log('\n=== Screen ===');
const scr = getScreenInfo();
Object.entries(scr).forEach(([k,v]) => console.log(`  ${k}: ${v}`));

